--
-- 테이블 구조 `tb_user`
--

CREATE TABLE `tb_user` (
  `mem_idx` int(10) UNSIGNED NOT NULL COMMENT 'P.K',
  `mem_uid` varchar(256) DEFAULT '' COMMENT '가입한 유저의 유니크한 값',
  `mem_userid` varchar(20) DEFAULT NULL COMMENT '로그인 ID',
  `mem_email` varchar(256) DEFAULT '' COMMENT '이메일',
  `mem_birth` varchar(256) DEFAULT '' COMMENT '고객 생년월일',
  `mem_phone` varchar(256) DEFAULT NULL COMMENT '고객 핸드폰 전화번호',
  `mem_phone4` varchar(255) NOT NULL DEFAULT '' COMMENT '전화번호뒤 4자리',
  `mem_homeaddress` varchar(255) DEFAULT '' COMMENT '고객 집주소',
  `mem_password` varchar(256) DEFAULT '' COMMENT '비밀번호(MD5 암호화로 32자리 고정처리)',
  `mem_cert` enum('Y','N') NOT NULL DEFAULT 'N' COMMENT '[임시조치]무언가 결제했는지 체크 Y:결제완료 N:결제안됨	',
  `mem_username` varchar(256) NOT NULL COMMENT '사용자 이름(비실명제일 경우 닉네임과 같은 값)',
  `mem_nickname` varchar(256) DEFAULT NULL COMMENT '업체명',
  `mem_gender` enum('M','F','U') NOT NULL DEFAULT 'U' COMMENT 'M:남성 F:여성 U:알수없음',
  `mem_level` smallint(5) UNSIGNED NOT NULL DEFAULT 1 COMMENT '사용자 레벨',
  `mem_auth` int(10) UNSIGNED NOT NULL DEFAULT 111 COMMENT '사용자 권한 레벨 ex) 운영자, 중간운영자, 하위운영자',
  `mem_point` int(10) UNSIGNED NOT NULL DEFAULT 0 COMMENT '사용자 포인트',
  `mem_regtime` datetime DEFAULT current_timestamp() COMMENT '회원가입일시',
  `mem_regip` int(10) UNSIGNED DEFAULT NULL COMMENT 'long 형식의 아이피주소',
  `mem_reg_newips` varchar(255) NOT NULL DEFAULT '' COMMENT '접속IP 목록',
  `mem_photo` varchar(200) DEFAULT '' COMMENT '회원 프로필경로',
  `mem_droptime` datetime DEFAULT NULL COMMENT '탈퇴 접근거부 실행일시',
  `mem_passchangetime` datetime DEFAULT NULL COMMENT '마지막 비밀번호 변경일시',
  `mem_is_admin` enum('Y','N') NOT NULL DEFAULT 'N' COMMENT '최고관리 권한을 갖고 있는가?',
  `mem_islogin` enum('Y','N') NOT NULL DEFAULT 'N' COMMENT '로그인을 1번이라도 했는지 여부',
  `mem_groupcode` varchar(30) NOT NULL COMMENT '내 레벨에 따른 그룹 권한 코드',
  `mem_groupidx` int(11) NOT NULL COMMENT '내그룹ID인덱스',
  `mem_centercodes` text NOT NULL COMMENT '등록한 센터 코드들',
  `mem_projectids` varchar(255) NOT NULL COMMENT '최대 10개 프로젝트콤마로 구분',
  `mem_fcmtoken` varchar(1000) DEFAULT '' COMMENT '단말기 FCM 토큰값',
  `mem_setting` text DEFAULT NULL COMMENT '어드민세팅화면 권한을 설정한다.',
  `mem_alert` text DEFAULT NULL COMMENT '개인적인 공지사항 푸시알람등..',
  `mem_other` text DEFAULT NULL COMMENT '기타 메모한 내용들'
) ENGINE=InnoDB DEFAULT CHARSET=utf8;

--
-- 테이블의 덤프 데이터 `tb_user`
